import React, { useState, useEffect } from 'react';

/**
 * DownloadExpirationStatus Component - Shows remaining time before download expires
 * Allows users to manually delete downloads before auto-expiration
 */
function DownloadExpirationStatus({ downloads = [], onRefresh = null }) {
  const [expandedDownload, setExpandedDownload] = useState(null);
  const [deleting, setDeleting] = useState(null);

  if (!downloads || downloads.length === 0) {
    return (
      <div className="bg-blue-50 border border-blue-200 rounded-lg p-4 text-center">
        <p className="text-gray-600 text-sm">ℹ️ No active downloads at the moment.</p>
      </div>
    );
  }

  const handleDeleteDownload = async (downloadId) => {
    if (window.confirm('Delete this download? It will be permanently removed.')) {
      setDeleting(downloadId);
      try {
        const token = localStorage.getItem('token');
        const response = await fetch(`/api/files/expiration/download/${downloadId}`, {
          method: 'DELETE',
          headers: {
            'Authorization': `Bearer ${token}`,
            'Content-Type': 'application/json'
          }
        });

        if (response.ok) {
          alert('Download deleted successfully');
          if (onRefresh) onRefresh();
        } else {
          const error = await response.json();
          alert(`Failed: ${error.error || 'Unknown error'}`);
        }
      } catch (err) {
        alert(`Error: ${err.message}`);
      } finally {
        setDeleting(null);
      }
    }
  };

  const getExpirationStatus = (download) => {
    if (!download.remainingTime) {
      return { status: 'no-expiry', label: 'No expiry set', icon: '∞', color: 'blue' };
    }

    const ms = download.remainingTime.ms;
    if (ms <= 0) {
      return { status: 'expired', label: 'Expired - will be deleted automatically', icon: '⏱️', color: 'red' };
    }

    const hours = ms / 3600000;
    if (hours < 1) {
      return { status: 'urgent', label: 'Expires in less than 1 hour', icon: '⚠️', color: 'red' };
    }
    if (hours < 24) {
      return { status: 'warning', label: 'Expires within 24 hours', icon: '⏳', color: 'orange' };
    }

    return { status: 'active', label: 'Active', icon: '✓', color: 'green' };
  };

  const getColorClasses = (color) => {
    const colors = {
      red: 'bg-red-50 border-red-200 text-red-700',
      orange: 'bg-orange-50 border-orange-200 text-orange-700',
      green: 'bg-green-50 border-green-200 text-green-700',
      blue: 'bg-blue-50 border-blue-200 text-blue-700'
    };
    return colors[color] || colors.blue;
  };

  return (
    <div className="space-y-3">
      {downloads.map((download) => {
        const status = getExpirationStatus(download);
        const isExpanded = expandedDownload === download.file_id;

        return (
          <div
            key={`${download.file_id}-${download.id}`}
            className={`border rounded-lg p-3 transition ${getColorClasses(status.color)}`}
          >
            <div
              className="flex items-center justify-between cursor-pointer hover:opacity-80"
              onClick={() => setExpandedDownload(isExpanded ? null : download.file_id)}
            >
              <div className="flex items-center gap-3 flex-1">
                <span className="text-2xl">{status.icon}</span>
                <div className="flex-1 min-w-0">
                  <p className="font-semibold text-sm truncate">{download.originalname}</p>
                  <p className="text-xs opacity-75">{status.label}</p>
                </div>
              </div>
              <span className="text-lg">{isExpanded ? '−' : '+'}</span>
            </div>

            {isExpanded && (
              <div className="mt-3 pt-3 border-t border-current border-opacity-20 space-y-2">
                <div className="text-xs space-y-1">
                  <div className="flex justify-between">
                    <span className="opacity-75">File ID:</span>
                    <span className="font-mono">{download.file_id}</span>
                  </div>
                  <div className="flex justify-between">
                    <span className="opacity-75">Downloaded:</span>
                    <span>{new Date(download.downloaded_at).toLocaleString()}</span>
                  </div>
                  {download.remainingTime && (
                    <>
                      <div className="flex justify-between">
                        <span className="opacity-75">Expires:</span>
                        <span>{new Date(download.remainingTime.ms + Date.now()).toLocaleString()}</span>
                      </div>
                      <div className="flex justify-between font-semibold">
                        <span>Remaining:</span>
                        <span>{download.remainingTime.formatted}</span>
                      </div>
                    </>
                  )}
                  <div className="flex justify-between">
                    <span className="opacity-75">File exists:</span>
                    <span>{download.fileExists ? '✓ Yes' : '✗ No'}</span>
                  </div>
                </div>

                <div className="flex gap-2 mt-3">
                  <button
                    onClick={() => handleDeleteDownload(download.id)}
                    disabled={deleting === download.id}
                    className={`flex-1 px-3 py-1.5 rounded text-sm font-semibold text-white transition
                      ${deleting === download.id
                        ? 'bg-gray-400 cursor-not-allowed'
                        : 'bg-red-500 hover:bg-red-600'
                      }`}
                  >
                    {deleting === download.id ? 'Deleting...' : 'Delete Now'}
                  </button>
                  <button
                    onClick={() => setExpandedDownload(null)}
                    className="flex-1 px-3 py-1.5 rounded text-sm font-semibold bg-gray-300 hover:bg-gray-400 text-gray-800 transition"
                  >
                    Close
                  </button>
                </div>
              </div>
            )}
          </div>
        );
      })}
    </div>
  );
}

export default DownloadExpirationStatus;
